from django import forms
from django.contrib.auth.models import User
from django.contrib.auth.forms import UserCreationForm
from django.core.exceptions import ValidationError


class RegisterForm(UserCreationForm):
    email = forms.EmailField(
        required=True,
        widget=forms.EmailInput(attrs={
            'class': 'form-control',
            'placeholder': 'Correo electrónico'
        })
    )
    password1 = forms.CharField(
        label='Contraseña',
        widget=forms.PasswordInput(attrs={
            'class': 'form-control',
            'placeholder': 'Contraseña'
        })
    )
    password2 = forms.CharField(
        label='Confirmar contraseña',
        widget=forms.PasswordInput(attrs={
            'class': 'form-control',
            'placeholder': 'Confirmar contraseña'
        })
    )

    class Meta:
        model = User
        fields = ('email', 'password1', 'password2')

    def clean_email(self):
        email = self.cleaned_data.get('email')
        if User.objects.filter(email=email).exists():
            raise ValidationError('Este correo electrónico ya está registrado.')
        return email

    def clean_password2(self):
        password1 = self.cleaned_data.get('password1')
        password2 = self.cleaned_data.get('password2')
        if password1 and password2 and password1 != password2:
            raise ValidationError('Las contraseñas no coinciden.')
        return password2

    def save(self, commit=True):
        user = super().save(commit=False)
        user.username = self.cleaned_data['email']
        user.email = self.cleaned_data['email']
        if commit:
            user.save()
        return user


class LoginForm(forms.Form):
    email = forms.EmailField(
        widget=forms.EmailInput(attrs={
            'class': 'form-control',
            'placeholder': 'Correo electrónico'
        })
    )
    password = forms.CharField(
        label='Contraseña',
        widget=forms.PasswordInput(attrs={
            'class': 'form-control',
            'placeholder': 'Contraseña'
        })
    )

from django.shortcuts import render, redirect
from django.contrib.auth import authenticate, login, logout
from django.contrib.auth.decorators import login_required
from django.contrib.auth.models import User
from django.views.decorators.http import require_http_methods
from django.contrib import messages
from .forms import RegisterForm, LoginForm
from .models import ClienteProfile


@require_http_methods(['GET', 'POST'])
def register_view(request):
    if request.user.is_authenticated:
        return redirect('home')

    if request.method == 'POST':
        form = RegisterForm(request.POST)
        if form.is_valid():
            user = form.save()
            ClienteProfile.objects.create(user=user)
            login(request, user)
            messages.success(request, 'Registro exitoso. Bienvenido a Hundidos.')
            return redirect('home')
        else:
            for field, errors in form.errors.items():
                for error in errors:
                    messages.error(request, f'{field}: {error}')
    else:
        form = RegisterForm()

    return render(request, 'accounts/register.html', {'form': form})


@require_http_methods(['GET', 'POST'])
def login_view(request):
    if request.user.is_authenticated:
        return redirect('home')

    if request.method == 'POST':
        form = LoginForm(request.POST)
        if form.is_valid():
            email = form.cleaned_data['email']
            password = form.cleaned_data['password']

            try:
                user = User.objects.get(email=email)
                user = authenticate(request, username=user.username, password=password)
                if user is not None:
                    login(request, user)
                    messages.success(request, 'Sesión iniciada correctamente.')
                    return redirect('home')
                else:
                    messages.error(request, 'Correo o contraseña incorrectos.')
            except User.DoesNotExist:
                messages.error(request, 'Correo o contraseña incorrectos.')
    else:
        form = LoginForm()

    return render(request, 'accounts/login.html', {'form': form})


@require_http_methods(['POST'])
@login_required(login_url='accounts:login')
def logout_view(request):
    logout(request)
    messages.success(request, 'Sesión cerrada correctamente.')
    return redirect('home')


@login_required(login_url='accounts:login')
def profile_view(request):
    try:
        profile = request.user.cliente_profile
    except ClienteProfile.DoesNotExist:
        profile = ClienteProfile.objects.create(user=request.user)

    return render(request, 'accounts/profile.html', {'profile': profile})

{% extends 'base.html' %}

{% block title %}Inicio - Hundidos{% endblock %}

{% block content %}
<div class="hero">
    <div class="container">
        <h1 class="display-4 mb-4">Bienvenido a Hundidos</h1>
        <p class="lead mb-4">Alquila los mejores barcos para tus aventuras en el mar</p>
        <a href="{% url 'catalog:barco_list' %}" class="btn btn-light btn-lg">Explorar Catálogo</a>
    </div>
</div>

<div class="container my-5">
    <h2 class="text-center mb-5">Nuestros Barcos Destacados</h2>
    <div class="row">
        {% for barco in barcos %}
            <div class="col-md-4 mb-4">
                <div class="card h-100">
                    {% if barco.imagen %}
                        <img src="{{ barco.imagen.url }}" class="card-img-top" alt="{{ barco.nombre }}" style="height: 200px; object-fit: cover;">
                    {% else %}
                        <div class="card-img-top bg-secondary" style="height: 200px; display: flex; align-items: center; justify-content: center;">
                            <span class="text-white">Sin imagen</span>
                        </div>
                    {% endif %}
                    <div class="card-body">
                        <h5 class="card-title">{{ barco.nombre }}</h5>
                        <p class="card-text text-muted">{{ barco.categoria.nombre }}</p>
                        <p class="card-text">
                            <small class="text-muted">Fabricante: {{ barco.fabricante.nombre }}</small><br>
                            <small class="text-muted">Puerto: {{ barco.puerto.nombre }}</small><br>
                            <small class="text-muted">Capacidad: {{ barco.capacidad }} personas</small>
                        </p>
                        <h6 class="text-primary">{{ barco.precio_dia }}€ / día</h6>
                    </div>
                    <div class="card-footer bg-white">
                        <a href="{% url 'catalog:barco_detail' barco.id %}" class="btn btn-primary btn-sm w-100">Ver Detalles</a>
                    </div>
                </div>
            </div>
        {% empty %}
            <div class="col-12">
                <p class="text-center text-muted">No hay barcos disponibles en este momento.</p>
            </div>
        {% endfor %}
    </div>
</div>

<script>
    document.addEventListener('DOMContentLoaded', function() {
        fetch('{% url "catalog:barco_list" %}')
            .then(response => response.text())
            .then(html => {
                const parser = new DOMParser();
                const doc = parser.parseFromString(html, 'text/html');
                const barcos = doc.querySelectorAll('.card');
                const container = document.querySelector('.row');
                container.innerHTML = '';
                let count = 0;
                barcos.forEach(barco => {
                    if (count < 3) {
                        container.appendChild(barco.cloneNode(true));
                        count++;
                    }
                });
            })
            .catch(error => console.error('Error:', error));
    });
</script>
{% endblock %}

