{% block title %}{{ barco.nombre }} - Hundidos{% endblock %}

{% block content %}
<div class="container my-5">
    <div class="row">
        <div class="col-md-6">
            {% if barco.imagen %}
                <img src="{{ barco.imagen.url }}" class="img-fluid rounded" alt="{{ barco.nombre }}">
            {% else %}
                <div class="bg-secondary rounded" style="height: 400px; display: flex; align-items: center; justify-content: center;">
                    <span class="text-white">Sin imagen disponible</span>
                </div>
            {% endif %}
        </div>
        <div class="col-md-6">
            <h1>{{ barco.nombre }}</h1>
            <p class="text-muted">{{ barco.categoria.nombre }}</p>

            <div class="card mb-4">
                <div class="card-body">
                    <h5 class="card-title">Información del Barco</h5>
                    <p><strong>Fabricante:</strong> {{ barco.fabricante.nombre }} {% if barco.fabricante.pais %}({{ barco.fabricante.pais }}){% endif %}</p>
                    <p><strong>Puerto Base:</strong> {{ barco.puerto.nombre }} - {{ barco.puerto.ubicacion }}</p>
                    <p><strong>Capacidad:</strong> {{ barco.capacidad }} personas</p>
                    <p><strong>Precio:</strong> <span class="text-primary h4">{{ barco.precio_dia }}€ / día</span></p>
                </div>
            </div>

            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Reservar este Barco</h5>
                    <form method="post" action="{% url 'reservations:checkout_step1' %}">
                        {% csrf_token %}
                        <input type="hidden" name="barco_id" value="{{ barco.id }}">
                        <div class="mb-3">
                            <label for="cantidad" class="form-label">Cantidad de barcos</label>
                            <input type="number" class="form-control" id="cantidad" name="cantidad" value="1" min="1" max="10">
                        </div>
                        <button type="submit" class="btn btn-primary w-100">Continuar con la Reserva</button>
                    </form>
                </div>
            </div>
        </div>
    </div>

    <div class="row mt-5">
        <div class="col-12">
            <h3>Barcos Similares</h3>
            <div class="row mt-3">
                {% for similar in barcos_similares %}
                    <div class="col-md-3 mb-4">
                        <div class="card h-100">
                            {% if similar.imagen %}
                                <img src="{{ similar.imagen.url }}" class="card-img-top" alt="{{ similar.nombre }}" style="height: 150px; object-fit: cover;">
                            {% else %}
                                <div class="card-img-top bg-secondary" style="height: 150px; display: flex; align-items: center; justify-content: center;">
                                    <span class="text-white">Sin imagen</span>
                                </div>
                            {% endif %}
                            <div class="card-body">
                                <h6 class="card-title">{{ similar.nombre }}</h6>
                                <p class="card-text text-muted">{{ similar.precio_dia }}€ / día</p>
                            </div>
                            <div class="card-footer bg-white">
                                <a href="{% url 'catalog:barco_detail' similar.id %}" class="btn btn-sm btn-primary w-100">Ver</a>
                            </div>
                        </div>
                    </div>
                {% endfor %}
            </div>
        </div>
    </div>
</div>

<script>
    document.addEventListener('DOMContentLoaded', function() {
        const barcoId = {{ barco.id }};
        const categoriaId = {{ barco.categoria.id }};

        fetch(`{% url 'catalog:barco_list' %}?categoria=${categoriaId}`)
            .then(response => response.text())
            .then(html => {
                const parser = new DOMParser();
                const doc = parser.parseFromString(html, 'text/html');
                const barcos = doc.querySelectorAll('.card');
                const container = document.querySelector('.row:last-child .row');
                container.innerHTML = '';
                let count = 0;
                barcos.forEach(barco => {
                    if (count < 4 && !barco.textContent.includes('{{ barco.nombre }}')) {
                        container.appendChild(barco.cloneNode(true));
                        count++;
                    }
                });
            })
            .catch(error => console.error('Error:', error));
    });
</script>
{% endblock %}

